const result = await new Promise((resolve) => {
  require('https').get('https://bliybylxjwemgzjvazyc.supabase.co/storage/v1/object/public/snapshots/stock-history.json', (res) => {
    let data = '';
    res.on('data', d => data += d);
    res.on('end', () => { try { resolve(JSON.parse(data)); } catch (e) { resolve({ stockHistory: [] }); } });
  }).on('error', () => resolve({ stockHistory: [] }));
});
return [{ json: result }];

const result = await new Promise((resolve) => {
  require('https').get('https://raw.githubusercontent.com/crazyhorn888/stock-dashboard/main/data/concept-sectors.json', (res) => {
    let data = '';
    res.on('data', d => data += d);
    res.on('end', () => { try { resolve(JSON.parse(data)); } catch (e) { resolve({ concepts: {}, stocks: {} }); } });
  }).on('error', () => resolve({ concepts: {}, stocks: {} }));
});
return [{ json: result }];

const stockHistoryData = $('抓stock-history').item.json;
const conceptData = $('抓concept-sectors').item.json;

const stockHistory = stockHistoryData.stockHistory || [];
const covered = new Set(Object.keys(conceptData.stocks || {}));

const activityMap = {};
for (const day of stockHistory) {
  for (const s of (day.stocks || [])) {
    if (!activityMap[s.code]) activityMap[s.code] = { name: s.name, activity: 0 };
    activityMap[s.code].activity += Math.abs(s.net) + Math.abs(s.buySell);
  }
}

const isETF = code => code.startsWith('00');
const candidates = Object.entries(activityMap)
  .filter(([code]) => !covered.has(code) && !isETF(code))
  .map(([code, v]) => ({ code, name: v.name, activity: Math.round(v.activity) }))
  .sort((a, b) => b.activity - a.activity)
  .slice(0, 30);

return [{ json: { candidates, conceptNames: Object.keys(conceptData.concepts || {}) } }];

const { candidates, conceptNames } = $json;
const apiKey = $env.OPENAI_API_KEY;

const prompt = `你是台股產業分類專家。以下是既有的概念分類清單：
${conceptNames.join('、')}

請幫以下個股建議最適合的概念分類（可從既有清單選，或建議一個新概念名稱）。用 JSON 陣列回答，格式：
[{"code":"股票代號","concept":"建議概念名稱"}, ...]
只回傳 JSON，不要其他文字。

個股清單：
${candidates.map(c => `${c.code} ${c.name}`).join('\n')}`;

const body = JSON.stringify({
  model: 'gpt-5.4-mini',
  messages: [{ role: 'user', content: prompt }],
  max_tokens: 2000,
});

const https = require('https');
const result = await new Promise((resolve) => {
  const req = https.request({
    hostname: 'api.openai.com', path: '/v1/chat/completions', method: 'POST',
    headers: { Authorization: `Bearer ${apiKey}`, 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(body) },
  }, (res) => {
    let data = '';
    res.on('data', d => data += d);
    res.on('end', () => {
      try {
        const json = JSON.parse(data);
        const content = json.choices?.[0]?.message?.content || '[]';
        const match = content.match(/\[[\s\S]*\]/);
        resolve(match ? JSON.parse(match[0]) : []);
      } catch (e) { resolve([]); }
    });
  });
  req.on('error', () => resolve([]));
  req.write(body);
  req.end();
});

const suggestionByCode = Object.fromEntries(result.map(r => [r.code, r.concept]));
const items = candidates.map(c => ({
  code: c.code,
  name: c.name,
  activity: c.activity,
  suggestedConcepts: suggestionByCode[c.code] ? [suggestionByCode[c.code]] : [],
}));

return [{ json: { items } }];

const { items } = $json;
const SUPABASE_KEY = $env.SUPABASE_SERVICE_KEY;
const https = require('https');

const getResult = await new Promise((resolve) => {
  https.get({
    hostname: 'bliybylxjwemgzjvazyc.supabase.co',
    path: '/storage/v1/object/review/pending.json',
    headers: { Authorization: `Bearer ${SUPABASE_KEY}` },
  }, (res) => {
    let d = '';
    res.on('data', c => d += c);
    res.on('end', () => resolve({ status: res.statusCode, body: d }));
  }).on('error', () => resolve({ status: 0, body: '' }));
});

let pending = { batches: [] };
if (getResult.status === 200) {
  try { pending = JSON.parse(getResult.body); } catch (e) { /* keep default */ }
}
pending.batches = pending.batches || [];

const batchId = `${Date.now()}`;
pending.batches.push({ id: batchId, createdAt: new Date().toISOString(), items });

const body = JSON.stringify(pending);
await new Promise((resolve) => {
  const req = https.request({
    hostname: 'bliybylxjwemgzjvazyc.supabase.co',
    path: '/storage/v1/object/review/pending.json',
    method: 'POST',
    headers: {
      Authorization: `Bearer ${SUPABASE_KEY}`,
      'Content-Type': 'application/json',
      'Content-Length': Buffer.byteLength(body),
      'x-upsert': 'true',
    },
  }, (res) => { res.on('data', () => {}); res.on('end', resolve); });
  req.on('error', resolve);
  req.write(body);
  req.end();
});

return [{ json: { batchId, count: items.length } }];
